package org.firstinspires.ftc.teamcode.testingopmodes;

import com.qualcomm.robotcore.eventloop.opmode.LinearOpMode;
import com.qualcomm.robotcore.eventloop.opmode.TeleOp;

import android.util.Base64;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.util.zip.GZIPInputStream;

@TeleOp(name = "BadApple60FPS", group = "Robot")
public class BadApple60FPS extends LinearOpMode {
	private static final int WIDTH = 32;
	private static final int HEIGHT = 24;
	private static final int BYTES_PER_ROW = WIDTH / 8; // 4
	private static final int BITS_PER_FRAME = WIDTH * HEIGHT; // 768
	private static final int BYTES_PER_FRAME = BITS_PER_FRAME / 8; // 96
	private static final String DISPLAY_OFFSET = "        "; // space left of the frame

	// generated with opencv in python from video
	public static final String[] BAD_APPLE_CHUNKS = {
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			"",
			""
	};

	@Override
	public void runOpMode() throws InterruptedException {
		// at 60 fps approx 16 ms between frames
		telemetry.setMsTransmissionInterval(16);

		StringBuilder badAppleBase64 = new StringBuilder();
		for (String chunk : BAD_APPLE_CHUNKS) {
			badAppleBase64.append(chunk);
		}

		byte[] compressed = Base64.decode(badAppleBase64.toString(), Base64.DEFAULT);
		byte[] bad_apple_bytes;

		// convert base64 gzip to bytes
		try (GZIPInputStream gis = new GZIPInputStream(new ByteArrayInputStream(compressed));
			ByteArrayOutputStream baos = new ByteArrayOutputStream()) {
			byte[] buffer = new byte[1024];
			int len;
			while ((len = gis.read(buffer)) > 0) {
				baos.write(buffer, 0, len);
			}
			bad_apple_bytes = baos.toByteArray();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}

		int bad_apple_frames = bad_apple_bytes.length / BYTES_PER_FRAME;

		long lastCycleTime = System.nanoTime();
		int frame_number = 0;

		while (!isStopRequested()) {
			// loops
			if (frame_number >= (bad_apple_bytes.length / BYTES_PER_FRAME)) {
				frame_number = 0;
			}

			StringBuilder frame = new StringBuilder();

			// top of frame
			frame.append(DISPLAY_OFFSET);
			for (int i = 0; i < WIDTH + 2; i++) {
				frame.append("▄");
			}
			frame.append("\n");

			// bad apple and sides of frames
			for (int y = 0; y < HEIGHT / 2; y++) {
				int row1Index = y * 2 * BYTES_PER_ROW;
				int row2Index = (y * 2 + 1) * BYTES_PER_ROW;

				byte[] topBytes = new byte[BYTES_PER_ROW], bottomBytes = new byte[BYTES_PER_ROW];
				int frameOffset = frame_number * BYTES_PER_FRAME;

				// left side of frame
				frame.append(DISPLAY_OFFSET).append("█");

				// each byte in a row
				for (int x = 0; x < BYTES_PER_ROW; x++) {
					topBytes[x] = bad_apple_bytes[frameOffset + row1Index + x];
					bottomBytes[x] = bad_apple_bytes[frameOffset + row2Index + x];
					// 7th bit is first pixel, 0th bit is 8th pixel
					for (int bit = 7; bit >= 0; bit--) {
						boolean top = (topBytes[x] >> bit & 1) == 1;
						boolean bottom = (bottomBytes[x] >> bit & 1) == 1;

						if (top && bottom) {
							frame.append("█");
						} else if (!top && !bottom) {
							// this is the same width as a block character for some reason
							frame.append("\u200A\u200A\u200A\u200A\u200A\u200A\u200A");
						} else if (top) {
							frame.append("▀");
						} else {
							frame.append("▄");
						}
					}
				}

				// right side of frame
				frame.append("█\n");
			}

			// bottom of frame
			frame.append(DISPLAY_OFFSET);
			for (int i = 0; i < WIDTH + 2; i++) {
				frame.append("▀");
			}
			frame_number++;

			telemetry.addLine(frame.toString());

			// wait approx until ready for next frame
			while (System.nanoTime() - lastCycleTime < 16620000.0) {
				Thread.sleep(0, 10000); // 100th of a millisecond
			}

			telemetry.addLine("Frame " + frame_number + "/" + bad_apple_frames + "        " + "FPS: " + (1000000000.0 / (System.nanoTime() - lastCycleTime)));
			lastCycleTime = System.nanoTime();

			telemetry.update();
		}
	}
}
